import React from "react";
import { InputText, type InputTextProps } from "primereact/inputtext";
import type { IKitsInputText } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useLanguage, useComponentDefaults, useResolvedStyle } from "../../../hooks";
import { ClHelper } from "../../helpers/Functions";
import { useSeparator } from "../../../factory";
import { useFormInputController } from "../../helpers/useFormInputController";

const KitsInputText = ({ ref, ...rawProps }: IKitsInputText) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('InputText', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        label,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        ignoreDirection,
        hideError,
        required,
        keyFilter,
        value,
        defaultValue,
        attached,
        onChange,
        isChecked,
        disabled,
        helperText,
        isFloatedLabel,
        inputSize,
        placeholder,
        containerStyle,
        localProps,
        keyboardType: _keyboardType, // native-only — consumed and discarded on web
        ...rest
    } = props;

    const { isRTL } = useLanguage();

    /** 🔑 unified control logic */
    const { value: displayValue, emitChange } =
        useFormInputController<string>({
            value,
            defaultValue,
            onChange,
        });

    const ClState = ClHelper({
        inputSize: inputSize ?? "",
        isChecked: !!isChecked,
        isInvalid: !!invalid,
        isDisabled: !!disabled,
    });

    const { nativeProps } = useSeparator<InputTextProps>(rest);

    const dirClass = isRTL && !ignoreDirection ? "text-right" : "";

    const Element = <InputText
        ref={ref}
        className={`w-full ${dirClass} ${ClState}`}
        style={{ borderRadius: 0, border:'none', ...resolvedRootStyle }}
        value={displayValue ?? ""}
        {...nativeProps}
        {...(localProps as any)}
        onChange={(e) => {
            emitChange(
                (e as any).target?.value ?? ""
            );
        }}
        keyfilter={keyFilter}
        placeholder={placeholder}
        disabled={disabled}
    />

    if(attached){
        return Element
    }

    return (
        <KitsContainer
            id={id}
            disabled={disabled}
            hideError={hideError}
            isFloatedLabel={isFloatedLabel}
            helperText={helperText}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            errors={errors}
            invalid={invalid}
            label={label}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputText;
